        stallLimit: 3,
        writer: memoryTraceWriter("memory://stall-breaker.ndjson"),
      },
    );
    const actions = run.trace.turns.map((turn) => turn.action.kind);

    expect(actions.slice(0, 3)).toEqual(["wait", "wait", "move"]);
  });
});

