        Pick<HoardFeatureParams, "hint">;
    };

export const startRun = (
  seed: string,
  provider: FloorContentProvider,
  options: RunStartOptions = {}
): RunLoopResult => {
  const gameConfig = options.config ?? defaultConfig;
  const state = turnStart(seed, { config: gameConfig });

  return enterFloor(state, provider, state.run.depth, gameConfig);
};

export const stepRun = (
  state: GameState,
  action: RunAction,
  provider: FloorContentProvider,
  options: RunStepOptions = {}
): RunLoopResult => {
  const gameConfig = options.config ?? defaultConfig;

  if (action.kind === "take_hoard") {
    const resolved = takeOneThingAtHoard(state);
    if ("illegal" in resolved) {
      return success(state, [
        runEvent(state.run.turn, "run_action_illegal", {
          actionKind: action.kind,
          reason: resolved.reason
        })
      ]);
    }

    const events = [
      runEvent(state.run.turn, "run_action_resolved", {
        actionKind: action.kind
      }),
      ...resolved.events
    ];

    return success(appendRunLog(resolved.state, events), events);
  }

  if (
    action.kind === "descend" &&
    state.run.depth >= gameConfig.runStructure.depthFloors
  ) {
    return success(state, [
      runEvent(state.run.turn, "run_action_illegal", {
        actionKind: action.kind,
        reason: "the final floor ends at the Hoard, not the stairs"
      })
    ]);
  }

  const stepped = turnStep(state, action, { hooks: options.hooks });
  if (
    actionWasIllegal(stepped.events) ||
    stepped.state.run.terminalStatus !== "ACTIVE"
  ) {
    return success(stepped.state, stepped.events);
  }

  if (action.kind === "descend") {
    const nextDepth = state.run.depth + 1;
    const entered = enterFloor(stepped.state, provider, nextDepth, gameConfig);
    if (!entered.ok) {
      return entered;
    }

    return success(entered.state, [...stepped.events, ...entered.events]);
  }

  const softCap = applySoftCap(stepped.state, gameConfig);
  return success(softCap.state, [...stepped.events, ...softCap.events]);
};

export const currentFloorRuntime = (state: GameState): FloorRuntime | null =>
  runtimeOpaque(state)?.knowledge?.run ?? null;

const enterFloor = (
  state: GameState,
  provider: FloorContentProvider,
  depth: number,
  gameConfig: GameConfig
): RunLoopResult => {
  if (depth < 1 || depth > gameConfig.runStructure.depthFloors) {
    return failure(state, {
      kind: "run-loop-error",
      code: "depth_out_of_range",
      depth,
      message: `depth ${depth} is outside run depth 1-${gameConfig.runStructure.depthFloors}`
    });
  }

  const band = depthBandForDepth(depth, gameConfig);
  const contentSeed = floorSeed(state.run.seed, depth);
  const contentResult = loadFloorContent(
    provider,
    depth,
    band,
    contentSeed,
    gameConfig
  );

  if (!contentResult.ok) {
    return failure(state, contentResult.error);
  }

  const generated = generateFloor(contentResult.content.params, gameConfig);
  if (!generated.ok) {
    return failure(state, {
      kind: "run-loop-error",
      code: "floor_generation_failed",
      depth,
      message: generated.error.message
    });
  }

  const requests = contentRequests(contentResult.content);
  const allocation = allocateCells(
    placementGrid(generated.floor),
    requests.map(({ request }) => request),
    runRng(state.run.seed).fork(`place:${depth}`)
  );

  if (!allocation.ok) {
    return failure(state, {
      kind: "run-loop-error",
      code: "placement_failed",
      depth,
      message: allocation.error.message
    });
  }

  const assembled = assembleEntities(
    state.ids.entityCounters,
    requests,
    allocation.placements
  );
  const hoard = hoardRuntime(requests, allocation.placements);
  const runtime: FloorRuntime = {
    depth,
    enteredTurn: state.run.turn,
    seed: contentSeed,
    entrance: generated.floor.entrance,
    stairsDown: generated.floor.stairsDown,
    roster: contentResult.content.roster,
    initialSpawnBudgetSpent: rosterCost(contentResult.content.roster),
    reinforcementSpawnBudgetSpent: 0,
    hoard
  };
  const floorId = `floor#${depth}`;
  const nextState = appendRunLog(
    {
      ...state,
      run: {
        ...state.run,
        depth,
        band
      },
      floor: {
        floorId,
        depth,
        band,
        geometry: createRuntimeGeometrySlot(
          `floor-geometry#${depth}`,
          generated.floor.grid,
          runtime
        )
      },
      player: {
        ...state.player,
        position: generated.floor.entrance
      },

import { config } from "../config/index.js";
import type {
  FloorContent,
  FloorContentProvider,
  HoardFeatureParams,
} from "../engine/run/loop.js";
import {
  FallbackContentValidationError,
  getFallbackFloor,
  loadFallbackContentPack,
  type FallbackContentPack,
  type ResolvedFallbackFloor,
} from "./content-loader.js";

export type FallbackProviderErrorCode =
  | "fallback_content_invalid"
  | "fallback_depth_unavailable";

export class FallbackProviderError extends Error {
  readonly kind = "fallback-provider-error";
  readonly code: FallbackProviderErrorCode;
  readonly depth: number | null;
  readonly file: string | null;
  readonly entityId: string | null;
  readonly source: unknown;

  constructor(
    code: FallbackProviderErrorCode,
    depth: number | null,
    message: string,
    source: unknown,
  ) {
    super(message);
    this.name = "FallbackProviderError";
    this.code = code;
    this.depth = depth;
    this.source = source;

    if (source instanceof FallbackContentValidationError) {
      this.file = source.file;
      this.entityId = source.entityId;
      return;
    }

    this.file = null;
    this.entityId = null;
  }
}

export type FallbackFloorContentProviderOptions = {
  readonly root?: URL;
  readonly hoard?: HoardFeatureParams;
};

const DEFAULT_HOARD: HoardFeatureParams = {
  id: "hoard",
  name: "The Hoard",
  hint: { distance: "far_from_entrance" },
};

export class FallbackFloorContentProvider implements FloorContentProvider {
  readonly pack: FallbackContentPack;
  private readonly floors: ReadonlyMap<number, ResolvedFallbackFloor>;
  private readonly hoard: HoardFeatureParams;

  constructor(options: FallbackFloorContentProviderOptions = {}) {
    this.hoard = options.hoard ?? DEFAULT_HOARD;

    try {
      this.pack = loadFallbackContentPack(options.root);
      this.floors = validateFloors(this.pack);
    } catch (error) {
      if (error instanceof FallbackProviderError) {
        throw error;
      }

      throw wrapProviderError("fallback_content_invalid", null, error);
    }
  }

  getFloor(depth: number, seed: string): FloorContent {
    const floor = this.floors.get(depth);
    if (floor === undefined) {
      throw new FallbackProviderError(
        "fallback_depth_unavailable",
        depth,
        `fallback floor ${depth} is not available`,
        null,
      );
    }

    return {
      params: {
        ...floor.params,
        seed,
        ...(depth === config.runStructure.depthFloors
          ? { hoard: this.hoard }
          : {}),
      },
      roster: floor.roster,
      items: floor.items,
      traps: floor.traps,
      npcs: floor.npcs,
      ...(floor.quest === null ? {} : { quest: floor.quest }),
    };
  }
}

export const createFallbackFloorContentProvider = (
  options: FallbackFloorContentProviderOptions = {},
): FallbackFloorContentProvider => new FallbackFloorContentProvider(options);

const validateFloors = (
  pack: FallbackContentPack,
): ReadonlyMap<number, ResolvedFallbackFloor> => {
  const floors = new Map<number, ResolvedFallbackFloor>();

  for (let depth = 1; depth <= config.runStructure.depthFloors; depth += 1) {
    try {
      floors.set(depth, getFallbackFloor(pack, depth));
    } catch (error) {
      throw wrapProviderError("fallback_content_invalid", depth, error);
    }
  }

  return floors;
};

const wrapProviderError = (
  code: FallbackProviderErrorCode,
  depth: number | null,
  source: unknown,
): FallbackProviderError => {
  const sourceMessage = source instanceof Error ? source.message : String(source);
  const message =
    depth === null
      ? `fallback content pack is invalid: ${sourceMessage}`
      : `fallback floor ${depth} is invalid: ${sourceMessage}`;

  return new FallbackProviderError(code, depth, message, source);
};

