export const Terrain = {
  Floor: "floor",
  Wall: "wall",
  Door: "door",
  Water: "water",
  StairsDown: "stairs_down",
  Entrance: "entrance",
} as const;

export type TerrainKind = (typeof Terrain)[keyof typeof Terrain];

export type DoorState = "open" | "closed";

export type Tile = {
  readonly terrain: TerrainKind;
  readonly door: DoorState | null;
};

export const TERRAIN_KINDS = [
  Terrain.Floor,
  Terrain.Wall,
  Terrain.Door,
  Terrain.Water,
  Terrain.StairsDown,
  Terrain.Entrance,
] as const satisfies readonly TerrainKind[];

export const TERRAIN_WALKABLE = {
  [Terrain.Floor]: true,
  [Terrain.Wall]: false,
  [Terrain.Door]: true,
  [Terrain.Water]: true,
  [Terrain.StairsDown]: true,
  [Terrain.Entrance]: true,
} as const satisfies Record<TerrainKind, boolean>;

export const TERRAIN_TRANSPARENT = {
  [Terrain.Floor]: true,
  [Terrain.Wall]: false,
  [Terrain.Door]: false,
  [Terrain.Water]: true,
  [Terrain.StairsDown]: true,
  [Terrain.Entrance]: true,
} as const satisfies Record<TerrainKind, boolean>;

export const createTile = (
  terrain: TerrainKind,
  door: DoorState | null = null,
): Tile => ({
  terrain,
  door: terrain === Terrain.Door ? (door ?? "closed") : null,
});

export const cloneTile = (tile: Tile): Tile => ({
  terrain: tile.terrain,
  door: tile.terrain === Terrain.Door ? (tile.door ?? "closed") : null,
});

export const isWalkableTerrain = (terrain: TerrainKind): boolean =>
  TERRAIN_WALKABLE[terrain];

export const isTransparentTerrain = (terrain: TerrainKind): boolean =>
  TERRAIN_TRANSPARENT[terrain];

export const isWalkableTile = (tile: Tile): boolean =>
  TERRAIN_WALKABLE[tile.terrain];

export const isTransparentTile = (tile: Tile): boolean => {
  if (tile.terrain === Terrain.Door) {
    return tile.door === "open";
  }

  return TERRAIN_TRANSPARENT[tile.terrain];
};

import type { Position } from "../state/index.js";
import { getTile, idx, neighbors8, type TileGrid } from "./grid.js";
import { isWalkableTile, Terrain, type Tile } from "./terrain.js";

export type PathOptions = {
  readonly openDoors?: boolean;
  readonly isOccupied?: (position: Position) => boolean;
};

const CARDINAL_STEP_COST = 10;
const DIAGONAL_STEP_COST = 14;

// Neighbor expansion uses neighbors8 order: NW, N, NE, W, E, SW, S, SE (row-major
// offsets from grid.ts). Open-set ties break on f, then h, then y, then x.
const compareOpenNodes = (
  a: { f: number; h: number; position: Position },
  b: { f: number; h: number; position: Position },
): number => {
  if (a.f !== b.f) {
    return a.f - b.f;
  }

  if (a.h !== b.h) {
    return a.h - b.h;
  }

  if (a.position.y !== b.position.y) {
    return a.position.y - b.position.y;
  }

  return a.position.x - b.position.x;
};

const positionsEqual = (a: Position, b: Position): boolean =>
  a.x === b.x && a.y === b.y;

const stepCost = (from: Position, to: Position): number => {
  const dx = Math.abs(to.x - from.x);
  const dy = Math.abs(to.y - from.y);

  return dx !== 0 && dy !== 0 ? DIAGONAL_STEP_COST : CARDINAL_STEP_COST;
};

const octileHeuristic = (from: Position, to: Position): number => {
  const dx = Math.abs(to.x - from.x);
  const dy = Math.abs(to.y - from.y);
  const min = Math.min(dx, dy);
  const max = Math.max(dx, dy);

  return min * DIAGONAL_STEP_COST + (max - min) * CARDINAL_STEP_COST;
};

const isPassableTile = (tile: Tile, openDoors: boolean): boolean => {
  if (!isWalkableTile(tile)) {
    return false;
  }

  if (tile.terrain === Terrain.Door && tile.door === "closed" && !openDoors) {
    return false;
  }

  return true;
};

const isPassable = (
  grid: TileGrid,
  position: Position,
  options: PathOptions,
  exempt: Position,
): boolean => {
  if (!positionsEqual(position, exempt) && options.isOccupied?.(position)) {
    return false;
  }

  return isPassableTile(getTile(grid, position), options.openDoors ?? false);
};

export const path = (
  grid: TileGrid,
  from: Position,
  to: Position,
  options: PathOptions = {},
): readonly Position[] | null => {
  if (positionsEqual(from, to)) {
    return isPassable(grid, from, options, from) ? [from] : null;
  }

  if (
    !isPassable(grid, from, options, from) ||
    !isPassable(grid, to, options, from)
  ) {
    return null;
  }

  const goalIndex = idx(grid, to);
  const startIndex = idx(grid, from);

  const gScore = new Map<number, number>([[startIndex, 0]]);
  const cameFrom = new Map<number, number>();
  const closed = new Set<number>();

  type OpenNode = {
    index: number;
    position: Position;
    f: number;
    h: number;
  };

  const open: OpenNode[] = [
    {
      index: startIndex,
      position: from,
      f: octileHeuristic(from, to),
      h: octileHeuristic(from, to),
    },
  ];

  while (open.length > 0) {
    open.sort(compareOpenNodes);
    const current = open.shift();

    if (current === undefined) {
      break;
    }

    if (closed.has(current.index)) {
      continue;
    }

    if (current.index === goalIndex) {
      const route: Position[] = [to];
      let cursor = goalIndex;

      while (cursor !== startIndex) {
        const previous = cameFrom.get(cursor);

        if (previous === undefined) {
          return null;
        }

        cursor = previous;
        route.push({
          x: cursor % grid.width,
          y: Math.floor(cursor / grid.width),
        });
      }

      route.reverse();
      return route;
    }

    closed.add(current.index);

    const currentG = gScore.get(current.index) ?? Number.POSITIVE_INFINITY;

    for (const neighbor of neighbors8(grid, current.position)) {
      const neighborIndex = idx(grid, neighbor);

      if (closed.has(neighborIndex)) {
        continue;
      }

      if (!isPassable(grid, neighbor, options, from)) {
        continue;
      }

      const tentativeG = currentG + stepCost(current.position, neighbor);
      const knownG = gScore.get(neighborIndex);

      if (knownG !== undefined && tentativeG >= knownG) {
        continue;
      }

      cameFrom.set(neighborIndex, current.index);
      gScore.set(neighborIndex, tentativeG);

      const h = octileHeuristic(neighbor, to);
      open.push({
        index: neighborIndex,
        position: neighbor,
        f: tentativeG + h,
        h,
      });
    }
  }

  return null;
};

import {
  config as defaultConfig,
  type GameConfig,
} from "../../config/index.js";
import type {
  FloorGeometrySlot,
  Position,
  SerializableRecord,
} from "../state/index.js";
import {
  cloneTile,
  createTile,
  Terrain,
  type TerrainKind,
  type Tile,
} from "./terrain.js";

export type TileGrid = {
  readonly kind: "tile-grid";
  readonly width: number;
  readonly height: number;
  readonly tiles: readonly Tile[];
};

export type MapDepthBand = keyof GameConfig["runStructure"]["floorGeometry"];

export type GridBounds = {
  readonly width: number;
  readonly height: number;
};

export type CreateTileGridOptions = GridBounds & {
  readonly fill?: TerrainKind | Tile;
  readonly tiles?: readonly Tile[];
};

export type CreateGridForBandOptions = {
  readonly config?: GameConfig;
  readonly fill?: TerrainKind | Tile;
};

const NEIGHBOR_OFFSETS_8 = [
  { x: -1, y: -1 },
  { x: 0, y: -1 },
  { x: 1, y: -1 },
  { x: -1, y: 0 },
  { x: 1, y: 0 },
  { x: -1, y: 1 },
  { x: 0, y: 1 },
  { x: 1, y: 1 },
] as const satisfies readonly Position[];

export const createTileGrid = ({
  width,
  height,
  fill = Terrain.Floor,
  tiles,
}: CreateTileGridOptions): TileGrid => {
  assertGridDimensions(width, height);
  const expectedTileCount = width * height;

  if (tiles !== undefined) {
    if (tiles.length !== expectedTileCount) {
      throw new RangeError(
        `tile count must equal width * height (${expectedTileCount})`,
      );
    }

    return {
      kind: "tile-grid",
      width,
      height,
      tiles: tiles.map(cloneTile),
    };
  }

  const fillTile = typeof fill === "string" ? createTile(fill) : cloneTile(fill);

  return {
    kind: "tile-grid",
    width,
    height,
    tiles: Array.from({ length: expectedTileCount }, () => cloneTile(fillTile)),
  };
};

export const createGridForBand = (
  band: MapDepthBand,
  options: CreateGridForBandOptions = {},
): TileGrid => {
  const gameConfig = options.config ?? defaultConfig;
  const geometry = gameConfig.runStructure.floorGeometry[band].grid;

  return createTileGrid({
    width: geometry.width,
    height: geometry.height,
    fill: options.fill,
  });
};

export const createFloorGeometrySlot = (
  refId: string,
  grid: TileGrid,
): FloorGeometrySlot => ({
  refId,
  opaque: grid as unknown as SerializableRecord,
});

export const inBounds = (bounds: GridBounds, position: Position): boolean =>
  Number.isSafeInteger(position.x) &&
  Number.isSafeInteger(position.y) &&
  position.x >= 0 &&
  position.x < bounds.width &&
  position.y >= 0 &&
  position.y < bounds.height;

export const idx = (grid: GridBounds, position: Position): number => {
  if (!inBounds(grid, position)) {
    throw new RangeError(`position (${position.x}, ${position.y}) out of bounds`);
  }

  return position.y * grid.width + position.x;
};

export const coord = (grid: GridBounds, index: number): Position => {
  if (!Number.isSafeInteger(index) || index < 0 || index >= grid.width * grid.height) {
    throw new RangeError(`index ${index} out of bounds`);
  }

  return {
    x: index % grid.width,
    y: Math.floor(index / grid.width),
  };
};

export const getTile = (grid: TileGrid, position: Position): Tile =>
  getTileAtIndex(grid, idx(grid, position));

export const getTileAtIndex = (grid: TileGrid, index: number): Tile => {
  const tile = grid.tiles[index];

  if (tile === undefined) {
    throw new RangeError(`tile index ${index} out of bounds`);
  }

  return tile;
};

export const withTile = (
  grid: TileGrid,
  position: Position,
  tile: Tile,
): TileGrid => {
  const index = idx(grid, position);
  const tiles = grid.tiles.map(cloneTile);
  tiles[index] = cloneTile(tile);

  return createTileGrid({
    width: grid.width,
    height: grid.height,
    tiles,
  });
};

export const neighbors8 = (
  grid: GridBounds,
  position: Position,
): readonly Position[] =>
  NEIGHBOR_OFFSETS_8.map((offset) => ({
    x: position.x + offset.x,
    y: position.y + offset.y,
  })).filter((neighbor) => inBounds(grid, neighbor));

export const line = (start: Position, end: Position): readonly Position[] => {
  assertPosition(start, "start");
  assertPosition(end, "end");

  const cells: Position[] = [];
  let x = start.x;
  let y = start.y;
  const dx = Math.abs(end.x - start.x);
  const sx = start.x < end.x ? 1 : -1;
  const dy = -Math.abs(end.y - start.y);
  const sy = start.y < end.y ? 1 : -1;
  let error = dx + dy;

  while (true) {
    cells.push({ x, y });

    if (x === end.x && y === end.y) {
      return cells;
    }

    const doubledError = 2 * error;

    if (doubledError >= dy) {
      error += dy;
      x += sx;
    }

    if (doubledError <= dx) {
      error += dx;
      y += sy;
    }
  }
};

export const discCells = (
  origin: Position,
  radius: number,
  bounds?: GridBounds,
): readonly Position[] => {
  assertPosition(origin, "origin");
  assertNonNegativeInteger(radius, "radius");

  const cells: Position[] = [];
  const radiusSquared = radius * radius;

  for (let y = origin.y - radius; y <= origin.y + radius; y += 1) {
    for (let x = origin.x - radius; x <= origin.x + radius; x += 1) {
      const position = { x, y };
      const dx = x - origin.x;
      const dy = y - origin.y;

      if (
        dx * dx + dy * dy <= radiusSquared &&
        (bounds === undefined || inBounds(bounds, position))
      ) {
        cells.push(position);
      }
    }
  }

  return cells;
};

export const radiusCells = discCells;

export const chebyshevDistance = (a: Position, b: Position): number =>
  Math.max(Math.abs(a.x - b.x), Math.abs(a.y - b.y));

export const distanceSquared = (a: Position, b: Position): number => {
  const dx = a.x - b.x;
  const dy = a.y - b.y;

  return dx * dx + dy * dy;
};

const assertGridDimensions = (width: number, height: number): void => {
  if (!Number.isSafeInteger(width) || width <= 0) {
    throw new RangeError("width must be a positive safe integer");
  }

  if (!Number.isSafeInteger(height) || height <= 0) {
    throw new RangeError("height must be a positive safe integer");
  }

  if (!Number.isSafeInteger(width * height)) {
    throw new RangeError("width * height must be a safe integer");
  }

