export const getFallbackFloor = (
  pack: FallbackContentPack,
  depth: number,
): ResolvedFallbackFloor => {
  const floor = pack.floors.get(depth);
  if (floor === undefined) {
    throw new FallbackContentValidationError(
      `${pack.root}/floors`,
      String(depth),
      `no floor definition for depth ${depth}`,
    );
  }

  const band = depthBandForDepth(depth);
  const fileLabel = `${pack.root}/floors/${depth}.json`;

  return {
    depth,
    band,
    flavor: floor.flavor,
    params: {
      bandOrSize: band,
      roomCountRange: config.runStructure.floorGeometry[band].rooms,
      flavor: floor.flavor,
    },
    roster: resolveReferences(
      fileLabel,
      floor.enemyRosterIds,
      pack.enemies,
      "enemy",
    ),
    items: resolveReferences(fileLabel, floor.itemIds, pack.items, "item"),
    traps: resolveReferences(fileLabel, floor.trapIds, pack.traps, "trap"),
    npcs: resolveReferences(fileLabel, floor.npcIds, pack.npcs, "npc"),
    quest:
      floor.questId === null
        ? null
        : (pack.quests.get(floor.questId) ??
          (() => {
            throw new FallbackContentValidationError(
              fileLabel,
              floor.questId,
              `unknown quest id ${floor.questId}`,
            );
          })()),
  };
};

  counters: EntityIdCounters,
  requests: readonly CandidateContentRequest[],
  placements: readonly PlacementAllocation[],
): { readonly counters: EntityIdCounters; readonly entities: EntityMap } => {
  let nextCounters = counters;
  const entities: Record<string, EntityInstance> = {};
  const byRequestId = new Map(
    requests.map((request) => [request.request.id, request]),
  );

  for (const placement of placements) {
    const request = byRequestId.get(placement.requestId);
    if (request === undefined) {
      continue;
    }

    const allocation = allocateEntityId(nextCounters, request.kind);
    nextCounters = allocation.entityCounters;

    switch (request.kind) {
      case "enemy": {
        const { placementHint: _placementHint, ...definition } = request.definition;
        const entity = assembleEnemy(definition, {
          id: allocation.id,
          position: placement.position,
        });
        entities[entity.id] = entity;
        break;
      }
      case "item": {
        const { placementHint: _placementHint, ...definition } = request.definition;
        const entity: GroundItemEntityInstance = {
          id: allocation.id,
          kind: "item",
          definition,
          position: placement.position,
          currentHP: null,
          statuses: [],
          behaviorRuntime: {},
          quantity: 1,
          identified: !["draught", "note", "charm"].includes(definition.kind),
        };
        entities[entity.id] = entity;
        break;
      }
      case "trap": {
        const { placementHint: _placementHint, ...definition } = request.definition;
        const entity: TrapEntityInstance = {
          id: allocation.id,
          kind: "trap",
          definition,
          position: placement.position,
          currentHP: null,
          statuses: [],
          behaviorRuntime: {},
          armed: true,
        };
        entities[entity.id] = entity;
        break;
      }
      case "npc": {
        const { placementHint: _placementHint, ...definition } = request.definition;
        const entity: NpcEntityInstance = {
          id: allocation.id,
          kind: "npc",
          definition,
          position: placement.position,
          currentHP: null,
          statuses: [],
          behaviorRuntime: {},
          dialogueRuntime: {},
        };
        entities[entity.id] = entity;
        break;
      }
    }
  }

  return {
    counters: nextCounters,
    entities,
  };
};

